diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..2f6fb199443e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1327,6 +1328,61 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       !match(ICmp2, m_ICmp(Pred2, m_Value(V2), m_APInt(C2))))
     return nullptr;

+  auto getRangeForPred = [&](CmpPredicate Pred, const APInt &C) {
+    return ConstantRange::makeExactICmpRegion(
+        IsAnd ? ICmpInst::getInverseCmpPredicate(Pred) : Pred, C);
+  };
+
+  auto getMaskedRange = [&](CmpPredicate Pred, const APInt &C, const APInt &Mask)
+      -> std::optional<ConstantRange> {
+    if (Pred == ICmpInst::ICMP_EQ)
+      return ConstantRange(C, C - Mask);
+    if (Pred == ICmpInst::ICMP_NE)
+      return ConstantRange(C, C - Mask).inverse();
+    return std::nullopt;
+  };
+
+  auto foldImpliedMaskedCompare = [&](Value *PlainV, CmpPredicate PlainPred,
+                                      const APInt &PlainC, ICmpInst *PlainICmp,
+                                      Value *MaskedV, CmpPredicate MaskedPred,
+                                      const APInt &MaskedC,
+                                      ICmpInst *MaskedICmp) -> Value * {
+    Value *X;
+    const APInt *Mask;
+    if (!match(MaskedV,
+               m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask)))))
+      return nullptr;
+    if (X != PlainV)
+      return nullptr;
+
+    ConstantRange PlainCR = ConstantRange::makeExactICmpRegion(PlainPred, PlainC);
+    std::optional<ConstantRange> MaskedCR =
+        getMaskedRange(MaskedPred, MaskedC, *Mask);
+    if (!MaskedCR)
+      return nullptr;
+
+    if (IsAnd) {
+      if (PlainCR.contains(*MaskedCR))
+        return MaskedICmp;
+      if (MaskedCR->contains(PlainCR))
+        return PlainICmp;
+      return nullptr;
+    }
+
+    if (PlainCR.contains(*MaskedCR))
+      return PlainICmp;
+    if (MaskedCR->contains(PlainCR))
+      return MaskedICmp;
+    return nullptr;
+  };
+
+  if (Value *V =
+          foldImpliedMaskedCompare(V1, Pred1, *C1, ICmp1, V2, Pred2, *C2, ICmp2))
+    return V;
+  if (Value *V =
+          foldImpliedMaskedCompare(V2, Pred2, *C2, ICmp2, V1, Pred1, *C1, ICmp1))
+    return V;
+
   // Look through add of a constant offset on V1, V2, or both operands. This
   // allows us to interpret the V + C' < C'' range idiom into a proper range.
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
@@ -1419,6 +1475,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

+
